		function sendReqAsync(content, callBack) {
    var msg;
    var objDoc;

    if (content == null)
        content = "";

    msg = "<http-envelope service='ProxyEngine' request='send' user-token='" + g_strToken + "'>" + content + "</http-envelope>";

    var hr = getHR();                 
    hr.open("POST", g_location + "ProxyEngine.aspx", true);
    hr.onreadystatechange = function() 
    { 
      //Resultado
      if (hr.readyState == 4) 
      {
        if (hr.status == 200) 
        {
            try 
            {
              objDoc = createDoc(hr.responseText);
            } catch (e) 
            {
              alert("sendReqAsync(): " + e.number + "  " + e.description);
						  enable_buttons();
					    return;
            }

            //Envia el resultado
            if (callBack)
              callBack(objDoc);
        } else 
        {
          alert("sendReqAsync(): ERROR " + hr.status);
				  enable_buttons();
			    return;
        }
      }
    };

    hr.send(msg);
}


function SQLGetAsync(qry, param, callBack) 
{                              
	sendReqAsync("<content-send SrvName=\"xquery\" Request=\"get-sql\" ><qry:declare xmlns:qry=\"nomad_engine.form\">"+param+"</qry:declare>"+qry+"</content-send>", function(doc) { 

    //Switchea las posibles respuestas
    strService  = doc.documentElement.attributes.getNamedItem("service").value;
    strResponse = doc.documentElement.attributes.getNamedItem("response").value;

    switch (strResponse) 
    {
        case "send-response":
          var eleResponse = doc.documentElement.childNodes.item(0);
          objResult = new NomadProxyResponse(eleResponse.attributes.getNamedItem("service").value, eleResponse.attributes.getNamedItem("response").value, eleResponse.childNodes.item(0));

					//Resultado                                       
          //Envia el resultado
          if (callBack)
            callBack(objResult.Message());
			    return;

        default:
          alert("invalid server reply, "+strResponse);
				  enable_buttons();
			    return;
    }
	});
}





var formEnabled = true;
var arrFILTER;
var arrMARK;
var pointCount;

function mark()
{
	//Mensaje
	disable_buttons("Marcando empleados de la lista...");


	//Optener el resultado
  exec_qry_async(
	  function(auxArr) 
	  { 
		  if (auxArr==null) return;

	   	//Quito los que no estan en la lista actual
	   	intersect(auxArr, arrFILTER);	

			//Validar la cantidad a marcar	   	
	   	if (auxArr.length > 1000)
	   	{
        alert("Demasiados registro a marcar!");
			  enable_buttons();
		    return;
	   	}

			var cnt=0;
		  for (var n=0; n<auxArr.length; n++)
		  {    
        if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",auxArr[n])==null) 
        {
        	Ctrl("arrcheckFILTER").AddRow().SetAttr("ID",auxArr[n]);                                       
        	cnt++;
        }
		  }            

		  refreshList(cnt ? " (se marcaron " + cnt+ " registros nuevos)" : " (no se marcaron nuevos registros)");
	  }
  );
}


//Generar la lista de Legajos
function WhereLegajos()
{
  var listLegajos,Where,t,subTxt,aux0,aux1,whereIN;
  Where="";
	WhereIN="";  


  listLegajos=Ctrl('listlegajos').GetXValue();
  if (listLegajos!="")
  {
    listLegajos=Replace(listLegajos,",",";").split(";");

    for (t=0; t<listLegajos.length; t++)
    { 
      if (listLegajos[t].indexOf("-")>=0)
      {
        subTxt=listLegajos[t].split("-");
        aux0=parseInt(subTxt[0],10);
        aux1=parseInt(subTxt[1],10);

        if ((!isNaN(aux0)) || (!isNaN(aux1)))
        {
            if (Where!="") Where+=" OR ";
          Where+="(";
            if (!isNaN(aux0)) Where+="LEG.e_numero_legajo >= "+aux0;
            if ((!isNaN(aux0)) && (!isNaN(aux1))) Where+=" AND ";
            if (!isNaN(aux1)) Where+="LEG.e_numero_legajo <= "+aux1;
          Where+=")";
        }
      } else
      {                           
        aux0=parseInt(listLegajos[t],10);
        if (!isNaN(aux0)) 
        {
          if (WhereIN!="") WhereIN+=",";
          WhereIN+=aux0;
        }
      }
    }
  }                                
  //Soporte para el IN
  Where = Where + (WhereIN ? (Where ? " OR " : "") + "LEG.e_numero_legajo in ("+WhereIN+")" : "");

  Ctrl("leg_where").SetXValue(Where);
}


//Generar la lista de Legajos
function WhereNombres()
{
  var Where, Last, Sep;
  Where="";      
  Last="";
  Sep="";

  var nombre=Ctrl('nombre').GetXValue().toUpperCase();
  for(var t=0; t<nombre.length; t++)
  {
    if (nombre.substr(t,1)>='A' && nombre.substr(t,1)<='Z')
    	Last += nombre.substr(t,1);
    else
  	if (Last != "")
  	{
			Where+=Sep + "contain(ucase(PER.d_ape_y_nom), \\'" + Last+ "\\')";
  		Last=""; Sep=" AND ";
  	}
  }
	if (Last != "")
		Where+=Sep + "contain(ucase(PER.d_ape_y_nom), \\'" + Last+ "\\')";

  Ctrl("nom_where").SetXValue(Where);      
}


function PREV_exec_qry()
{
  return null;
}


function POST_exec_qry(resultArray)
{
  return;
}

var LastExternParams = "";
var LastExternResult = "";

function exec_qry_async(callBackFunction)
{
  var np, i;
  var start = new Date();

  np = GetProxy();
  var qry = Ctrl("main").getResource("qry_" + Ctrl("tab_filtro").GetSelectedPanelID());	
  var qryMembers = qry.split("##");
  var qryMembers = qryMembers[1].split(",");
  var qryExt = null;

  var MyMSG = PREV_exec_qry();
  if (MyMSG)
  {
    alert(MyMSG);
	  enable_buttons();
    return;
  }

  var MaxSize = 0;
  if (Ctrl("maxsize"))
  {               
    MaxSize = parseInt(Ctrl("maxsize").GetXValue()); 
    if (MaxSize ? false : true) MaxSize = 100;
    Ctrl("maxsize").SetXValue(MaxSize.toString());
  }

	//Validaciones externas                     
  var nmdDATAExtern=new NomadXML("PARAM");
  if (Ctrl("main").getResource("qry_externo"))
  {
  	if (MaxSize)
  	{
	    alert("ERROR, qry_externo no soportado en modo BASIC!!!");
		  enable_buttons();
	    return;
    }

    qryExt = Ctrl("main").getResource("qry_externo");
    var qryMembersExt = qryExt.split("##");
    qryMembersExt = qryMembersExt[1].split(",");

    for (i=0; i<qryMembersExt.length; i++)
    {
	    if(Ctrl(qryMembersExt[i]))
	    {
	      if (Ctrl(qryMembersExt[i]).m_Required && Ctrl(qryMembersExt[i]).GetXValue()=="")
	      {
	        alert("El valor es requerido");
	        Ctrl(qryMembersExt[i]).SetFocus();
				  enable_buttons();
			    return;
	      }
      }
      nmdDATAExtern.SetAttr(qryMembersExt[i], Ctrl(qryMembersExt[i]).GetXValue());
    }
  }

	//Autowhere
  var nmdDATA=new NomadXML("PARAM");
  if (Ctrl("main").getResource("qry_autowhere"))
  {
    var qryAuto = Ctrl("main").getResource("qry_autowhere");
    var qryMembersAuto = qryAuto.split("##");
    qryMembersAuto = qryMembersAuto[1].split(",");
    var SOURCE = { };

    for (i=0; i<qryMembersAuto.length; i++)
    {                       
    	if(Ctrl(qryMembersAuto[i]))
    	{
	      if (Ctrl(qryMembersAuto[i]).m_Required && Ctrl(qryMembersAuto[i]).GetXValue()=="")
	      {
	        alert("El valor es requerido");
	        Ctrl(qryMembersAuto[i]).SetFocus();
				  enable_buttons();
			    return;
	      }
	      nmdDATA.SetAttr(qryMembersAuto[i], Ctrl(qryMembersAuto[i]).GetXValue());
	      SOURCE[qryMembersAuto[i]] = Ctrl(qryMembersAuto[i]).GetXValue(); 
      }
    }

		var SQLTest=qryAuto.split("$$")[1];
		var SQLFinal="";

	  var cur = 0, pos;
	  while(true) 
	  {   

	    pos = SQLTest.indexOf("{%=", cur);
	    if (pos < 0) { SQLFinal+=SQLTest.substr(cur); break; }

			SQLFinal+=SQLTest.substr(cur, pos);
	    cur = pos+3;
	    pos = SQLTest.indexOf("%}", cur); 

	    var MyEVAL = eval(SQLTest.substr(cur, pos-cur));
	    SQLFinal += MyEVAL;

	    cur = pos+2;
	  } 

    Ctrl("where").SetXValue(SQLFinal);
  }


	//Validaciones Basicas
  for (i=0; i<qryMembers.length; i++)
  {     
    if(Ctrl(qryMembers[i]))
    {
      if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
      {
        alert("El valor es requerido");
        Ctrl(qryMembers[i]).SetFocus();
			  enable_buttons();
		    return;
      }
      nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
    }
  }                  

  //Solo activos
  if(Ctrl("withACTIVE"))
  {
  	nmdDATA.SetAttr("activos", "1");
  	nmdDATAExtern.SetAttr("activos", "1");
  }


	//Consulta principal
	SQLGetAsync(
		qry, 
		nmdDATA.ToString(), 
		function(result) 
		{ 
		  var resultArray = STR2array(result);

		  // Ejecuta query EXTERNO
		  if (Ctrl("main").getResource("qry_externo"))
		  {           
		    if (LastExternParams == nmdDATAExtern.ToString())
		    {  
					var auxResult = STR2array(LastExternResult);
			    intersect(resultArray, auxResult);

			 		POST_exec_qry(resultArray);
			  	if (callBackFunction)
			  		callBackFunction(resultArray);		    
		    } else
		    {
			    SQLGetAsync(
			    	qryExt, 
			    	nmdDATAExtern.ToString(),
			    	function(result)
			    	{                          
			    		//Actualizo el CACHE    
			    		LastExternParams = nmdDATAExtern.ToString();   
			    		LastExternResult = result;

			    		//Analizo
					    var auxResult = STR2array(result);
					    intersect(resultArray, auxResult);

					 		POST_exec_qry(resultArray);
					  	if (callBackFunction)
					  		callBackFunction(resultArray);
			    	});
		    }

		  } else
		  {
		  	POST_exec_qry(resultArray);
		  	if (callBackFunction)
		  		callBackFunction(resultArray);
		  }       

		} 
	);
}


//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{
  var t;
  var tmp=new Array();

  //Creo la HASH
  for (t=0; t<arrayA.length; t++) 
  tmp["K"+arrayA[t]]=1;

  //Agrego los que no estan
  for (t=0; t<arrayB.length; t++) 
    if (tmp["K"+arrayB[t]]?false:true)
      arrayA.push(arrayB[t]);
}


//Elimina del Array A los elementos del Array B
function remove(arrayA, arrayB)
{
  var t;
  var tmp1=new Array();
  var tmp2=new Array();

  //Creo la HASH
  for (t=0; t<arrayB.length; t++) 
    tmp1["K"+arrayB[t]]=1;
  for (t=0; t<arrayA.length; t++) 
    tmp2.push(arrayA[t]);

  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (t=0; t<tmp2.length; t++)      
    if (tmp1["K"+tmp2[t]]?false:true)
      arrayA.push(tmp2[t]);
} 

//Elimina del Array A los elementos que no estan en el Array B
function intersect(arrayA, arrayB)
{
  var t;
  var tmp1=new Array();
  var tmp2=new Array();   

  //Creo la HASH
  for (t=0; t<arrayB.length; t++) 
    tmp1["K"+arrayB[t]]=1;
  for (t=0; t<arrayA.length; t++) 
    tmp2.push(arrayA[t]);

  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (t=0; t<tmp2.length; t++)      
  if (tmp1["K"+tmp2[t]]?true:false)
    arrayA.push(tmp2[t]);
}

//Elimina del Array A los elementos que no estan en el Array B
function copiar(arrayA, arrayB)
{
  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (var t=0; t<arrayB.length; t++)      
    arrayA.push(arrayB[t]);
}

//Transaforma un XML(tipo STRING) en ARRAY
function XML2array(xml)
{
  var arr = new Array();
  for (var cur=xml.FirstChild(); cur!=null; cur=cur.Next())
  arr.push(cur.GetAttr("id"));
  return arr;
}

//Transaforma un XML(tipo STRING) en ARRAY
function STR2array(str)
{
  var arr = new Array();

  var cur = 0, pos;
  while(true) 
  {
    pos = str.indexOf("id=\"", cur);
    if (pos < 0) break;

    cur = pos+4;
    pos = str.indexOf("\"", cur);
    arr.push(str.substr(cur, pos-cur));
    cur = pos+1;
  }

  /*
  for (var cur=xml.FirstChild(); cur!=null; cur=cur.Next())
  arr.push(cur.GetAttr("id"));
  */
  return arr;
}

//Function para activar y desactivar Botones
function enable_buttons(msg)
{ 
	if (Ctrl("listFILTER").SetMessage) Ctrl("listFILTER").SetMessage(null);
  CtrlEnabled("listFILTER_Delete", Ctrl("arrcheckFILTER").CountRow()==0?false:true);
  CtrlEnabled("listFILTER_Clear" , true);

  CtrlEnabled("vgroupDatosPers"  , true);
  CtrlEnabled("vgroupDatosCustom", true);        

  enable_custom_buttons();
  loadingMessage(false, null);
  formEnabled = true;

  Ctrl("filtrados").SetXValue("Legajos Filtrados: "+arrFILTER.length+(msg?msg:""));
}

function enable_custom_buttons()
{
}

//Function para activar y desactivar Botones
function disable_buttons(msg)
{                           
	loadingMessage(true, msg);
	Ctrl("filtrados").SetXValue(msg);
	if (Ctrl("listFILTER").SetMessage) Ctrl("listFILTER").SetMessage(msg);

  CtrlEnabled("vgroupDatosPers"  , false);
  CtrlEnabled("vgroupDatosCustom", false);        


  disable_custom_buttons();
  formEnabled = false;     
  pointCount = 0;
	pointAdd();  
}

function disable_custom_buttons()
{
}

function pointAdd()
{
	if (formEnabled) return;

	var msg = Ctrl("filtrados").GetXValue();
	msg += "."; pointCount++;               
	if (pointCount > 5) { msg = msg.substr(0,msg.length-pointCount); pointCount=0; }
	Ctrl("filtrados").SetXValue(msg);


	setTimeout(pointAdd, 200);
}


//Actualiza la lista con el nuevo ARRAY
function refreshList(msg)
{
  var page=Ctrl("listFILTER").Page;
  Ctrl("listFILTER").IDs=arrFILTER;
  Ctrl("listFILTER").ResetSQL();
  Ctrl("listFILTER").GotoPage(page);

  //Quito el mensaje
  enable_buttons(msg); 
}

function load()    
{       
	//Mensaje
	disable_buttons("Cargando empleados a la lista...");

	//Optener el resultado
  exec_qry_async(
	  function(auxArr) 
	  { 
		  if (auxArr==null) return;        

		  //Cargo el maxsize
		  var showMessage = false;
		  var MaxSize = 0;
		  if (Ctrl("maxsize")) MaxSize = parseInt(Ctrl("maxsize").GetXValue()); 

		  //Valido
		  if (MaxSize && auxArr.length > MaxSize)
		  {                         
	  		auxArr.length = MaxSize;
	  		showMessage = true;
		  }       

		  arrFILTER = auxArr; 
		  refreshList(showMessage?" (se cargaron los primeros " + auxArr.length + " registros)":"");
	  }
  );
}

function loadadd() 
{ 
	//Mensaje
	disable_buttons("Agregando empleados a la lista...");

	//Optener el resultado
  exec_qry_async(
	  function(auxArr) 
	  { 
		  if (auxArr==null) return;  

	   	//Quito los repetidos
		  remove(auxArr, arrFILTER);

		  //Cargo el maxsize      
		  var showMessage = false;
		  var MaxSize = 0;
		  if (Ctrl("maxsize")) MaxSize = parseInt(Ctrl("maxsize").GetXValue()); 

		  // Valido el tamaño
		  if (MaxSize)
		  {               
				//Valido
				if (auxArr.length + arrFILTER.length > MaxSize) 
				{       
		  		auxArr.length = MaxSize - arrFILTER.length;
		  		showMessage = true;
				}     
		  }

		  union(arrFILTER, auxArr);	
		  refreshList(auxArr.length ? (showMessage ? " (se cargaron los primeros " + auxArr.length+ " registros)": " (" + auxArr.length+ " registros agregados)") : " (no se agregaron registros)");
	  }
  );
}

function filter()  
{ 
	//Mensaje
	disable_buttons("Filtrando empleados de la lista...");

	//Optener el resultado
  exec_qry_async(
	  function(auxArr) 
	  { 
		  if (auxArr==null) return;  

		  intersect(arrFILTER, auxArr);	
		  refreshList();
	  }
  );
}

function find()
{ 
	//Mensaje
	disable_buttons("Buscando empleados en la lista...");


	//Optener el resultado
  exec_qry_async(
	  function(auxArr) 
	  { 
		  if (auxArr==null) return;  

		  //Obtiene los Elementos en Comun.
		  intersect(auxArr, arrFILTER);	
		  if (auxArr.length==0) 
		  {
		    alert("No se encontro ningun registro.");
				enable_buttons();
		    return;
		  }

			enable_buttons();		
		  Ctrl("listFILTER").SetXValue(auxArr[0]);
	  }
  );
}        





function ONLOAD()
{
  var t, ROW, VALUES;
  arrFILTER = new Array();

  //Valores Iniciales
  for (t=0; t<Ctrl("arrFILTER").CountRow(); t++)
  {
    ROW=Ctrl("arrFILTER").GetRow(t);
    VALUES=ROW.GetAttr("VALUES").split(",");
    for (d=0; d<VALUES.length; d++)
      if (VALUES[d]!="")
        arrFILTER.push(VALUES[d]);
  } 

  //Actualizo la Lista
  refreshList();       

  //Llamo el Custom
  ONLOAD_custom();

  habilitarAfiliado();

  //habilitarConfidenciales();  
}

