function FillArray(numByRow)
{
	var t,n,values,sep,row,p;    
	var np, nSQL;

	np = GetProxy();
	nSQL = np.SQLService();

	//lamo al QUERY que ORDENA....	
 	if (Ctrl("main").getResource("qry_orderby"))
 	{

 		//Genero el XML de PARAMETROS.
 		var nmdDATA=new NomadXML("PARAM");
		values=""; sep="";
		for (t=0,n=0; t<arrFILTER.length; t++, n++)
		{
			if (n>=300)
			{              
				nmdDATA.AddTailElement("ROW").SetAttr("VALUES", values);
				values=""; sep=""; n=0;
			}                  
			values+=sep+arrFILTER[t];
			sep=",";
		}
		if (values!="") 
		{      
			nmdDATA.AddTailElement("ROW").SetAttr("VALUES", values);
		}



 		var qry = Ctrl("main").getResource("qry_orderby");
		var qryMembers = qry.split("##");

		if(qryMembers.length>1)
		{

			qryMembers = qryMembers[1].split(",");          		


			for (i=0; i<qryMembers.length; i++)
			{
				if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
				{
					alert("El valor es requerido");
					Ctrl(qryMembers[i]).SetFocus();
					return null;
				}				
				nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
			}
		} 

  	var result = nSQL.Get(qry, nmdDATA.ToString());
    arrFILTER = STR2array(result);
 	}


	//Genero el XML del IN
	Ctrl("arrFILTER").DelAllRow(); 

	values=""; sep="";
	for (t=0,n=0,p=0; t<arrFILTER.length; t++, n++)
	{
		if (n>=numByRow)
		{              
			p++;
			row=Ctrl("arrFILTER").AddRow()
			row.SetAttr("id", p);
			row.SetAttr("VALUES", values);
			values=""; sep=""; n=0;
		}                  

		values+=sep+arrFILTER[t];
		sep=",";
	}
	if (values!="") 
	{      
		p++;
		row=Ctrl("arrFILTER").AddRow()
		row.SetAttr("id", p);
		row.SetAttr("VALUES", values);
	}

}

