//Habilita y desmarca el CheckBox l_afiliado_sind cuando hay un sindicato seleccionado
//Desmarca y deshabilita el checkbox l_afiliado_sind cuando no hay un sindicato seleccionado
function habilitarAfiliado()
{
  //Desmarca el Checck.
  Ctrl('l_afiliado_sind').SetXVal(0);
  Ctrl('l_afiliado_sind').SetCVal(0);

  if(Ctrl("sindicato").GetXValue()=='')
  {
